import{_ as t,c as i,o as a,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse(`{"title":"ToS Warning: Account Risks | opencode-antigravity-auth","description":"Learn the risks of using Antigravity Auth plugin. Understand Google's ToS restrictions, identify high-risk scenarios, and master best practices to avoid account bans and protect your Google account security.","frontmatter":{"title":"ToS Warning: Account Risks | opencode-antigravity-auth","sidebarTitle":"ToS Warning","subtitle":"ToS Warning: Account Risks","description":"Learn the risks of using Antigravity Auth plugin. Understand Google's ToS restrictions, identify high-risk scenarios, and master best practices to avoid account bans and protect your Google account security.","tags":["FAQ","risk-warning","account-security"],"prerequisite":["start-quick-install"],"order":5},"headers":[],"relativePath":"NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md","filePath":"NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"}`),n={name:"NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"};function s(r,e,l,c,u,d){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="tos-warning" tabindex="-1">ToS Warning <a class="header-anchor" href="#tos-warning" aria-label="Permalink to &quot;ToS Warning&quot;">​</a></h1><p>By completing this lesson, you&#39;ll understand the potential risks of using the Antigravity Auth plugin and how to protect your Google account security.</p><h2 id="your-current-challenge" tabindex="-1">Your Current Challenge <a class="header-anchor" href="#your-current-challenge" aria-label="Permalink to &quot;Your Current Challenge&quot;">​</a></h2><p>You&#39;re considering using the Antigravity Auth plugin to access Google Antigravity&#39;s AI models, but you have some concerns:</p><ul><li>You&#39;ve seen community reports of account bans or shadow bans</li><li>You&#39;re worried that using unofficial tools violates Google&#39;s Terms of Service</li><li>You&#39;re unsure whether to use a new account or an existing account</li><li>You want to know how to minimize the risk</li></ul><p>These concerns are reasonable. Using any unofficial tool carries some risk. This article will help you understand the specific risks and mitigation strategies.</p><h2 id="when-to-use-this-lesson" tabindex="-1">When to Use This Lesson <a class="header-anchor" href="#when-to-use-this-lesson" aria-label="Permalink to &quot;When to Use This Lesson&quot;">​</a></h2><ul><li><strong>Before installing the plugin</strong>: Understand the risks before deciding whether to use it</li><li><strong>When choosing an account</strong>: Decide which Google account to use for authentication</li><li><strong>When encountering a ban</strong>: Understand possible causes and preventive measures</li><li><strong>When registering new users</strong>: Avoid high-risk usage patterns</li></ul><hr><h2 id="core-risk-overview" tabindex="-1">Core Risk Overview <a class="header-anchor" href="#core-risk-overview" aria-label="Permalink to &quot;Core Risk Overview&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Important Warning</p><p><strong>Using this plugin may violate Google&#39;s Terms of Service.</strong></p><p>A small number of users have reported their Google accounts being banned or shadow banned (Shadow Ban—restricted access without explicit notification).</p><p><strong>By using this plugin, you accept the following statements:</strong></p><ol><li>This is an unofficial tool, not endorsed or approved by Google</li><li>Your Google account may be suspended or permanently banned</li><li>You assume all risks and consequences of using this plugin</li></ol></div><h3 id="what-is-shadow-banning" tabindex="-1">What Is Shadow Banning? <a class="header-anchor" href="#what-is-shadow-banning" aria-label="Permalink to &quot;What Is Shadow Banning?&quot;">​</a></h3><p><strong>Shadow Banning</strong> is a restriction measure Google takes against suspicious accounts. Unlike direct bans, shadow banning doesn&#39;t display explicit error messages. Instead:</p><ul><li>API requests return 403 or 429 errors</li><li>Quota appears available but actual calls fail</li><li>Other accounts work normally, only the flagged account is affected</li></ul><p>Shadow banning typically lasts for an extended period (days to weeks) and cannot be recovered through appeals.</p><hr><h2 id="high-risk-scenarios" tabindex="-1">High-Risk Scenarios <a class="header-anchor" href="#high-risk-scenarios" aria-label="Permalink to &quot;High-Risk Scenarios&quot;">​</a></h2><p>The following scenarios significantly increase the risk of accounts being flagged or banned:</p><h3 id="🚨-scenario-1-brand-new-google-account" tabindex="-1">🚨 Scenario 1: Brand New Google Account <a class="header-anchor" href="#🚨-scenario-1-brand-new-google-account" aria-label="Permalink to &quot;🚨 Scenario 1: Brand New Google Account&quot;">​</a></h3><p><strong>Risk Level: Very High</strong></p><p>Using a newly registered Google account with this plugin carries a very high probability of being banned. Reasons:</p><ul><li>New accounts lack historical behavior data and are easily flagged by Google&#39;s abuse detection system</li><li>Heavy API usage on new accounts is seen as abnormal behavior</li><li>Google scrutinizes new accounts more strictly</li></ul><p><strong>Recommendation</strong>: Do not create a new account specifically for this plugin.</p><h3 id="🚨-scenario-2-new-account-pro-ultra-subscription" tabindex="-1">🚨 Scenario 2: New Account + Pro/Ultra Subscription <a class="header-anchor" href="#🚨-scenario-2-new-account-pro-ultra-subscription" aria-label="Permalink to &quot;🚨 Scenario 2: New Account + Pro/Ultra Subscription&quot;">​</a></h3><p><strong>Risk Level: Very High</strong></p><p>Newly registered accounts that immediately subscribe to Google&#39;s Pro or Ultra services are often flagged and banned. Reasons:</p><ul><li>High-usage patterns after subscription appear as abuse on new accounts</li><li>Google scrutinizes new paid users more strictly</li><li>This pattern differs too much from normal user growth paths</li></ul><p><strong>Recommendation</strong>: Let the account &quot;naturally grow&quot; for a period (at least several months) before considering subscription.</p><h3 id="🟡-scenario-3-high-volume-requests-in-a-short-time" tabindex="-1">🟡 Scenario 3: High Volume Requests in a Short Time <a class="header-anchor" href="#🟡-scenario-3-high-volume-requests-in-a-short-time" aria-label="Permalink to &quot;🟡 Scenario 3: High Volume Requests in a Short Time&quot;">​</a></h3><p><strong>Risk Level: High</strong></p><p>Making a large number of API requests in a short time, or frequently using parallel proxies/multiple sessions, triggers rate limiting and abuse detection. Reasons:</p><ul><li>OpenCode&#39;s request pattern is more intensive than native applications (tool calls, retries, streaming, etc.)</li><li>High concurrent requests trigger Google&#39;s protection mechanisms</li></ul><p><strong>Recommendations</strong>:</p><ul><li>Control request frequency and concurrency</li><li>Avoid launching multiple parallel agents simultaneously</li><li>Use multiple account rotation to distribute requests</li></ul><h3 id="🟡-scenario-4-using-a-single-google-account" tabindex="-1">🟡 Scenario 4: Using a Single Google Account <a class="header-anchor" href="#🟡-scenario-4-using-a-single-google-account" aria-label="Permalink to &quot;🟡 Scenario 4: Using a Single Google Account&quot;">​</a></h3><p><strong>Risk Level: Medium</strong></p><p>If you only have one Google account and rely on it for critical services (Gmail, Drive, etc.), the risk is higher. Reasons:</p><ul><li>Account ban affects your daily work</li><li>Cannot recover through appeals</li><li>Lack of backup plans</li></ul><p><strong>Recommendation</strong>: Use a separate account that doesn&#39;t depend on critical services.</p><hr><h2 id="best-practice-recommendations" tabindex="-1">Best Practice Recommendations <a class="header-anchor" href="#best-practice-recommendations" aria-label="Permalink to &quot;Best Practice Recommendations&quot;">​</a></h2><h3 id="✅-recommended-practices" tabindex="-1">✅ Recommended Practices <a class="header-anchor" href="#✅-recommended-practices" aria-label="Permalink to &quot;✅ Recommended Practices&quot;">​</a></h3><p><strong>1. Use Established Google Accounts</strong></p><p>Prioritize Google accounts that have been in use for some time (recommended 6 months or more):</p><ul><li>Have normal Google service usage history (Gmail, Drive, Google Search, etc.)</li><li>No history of violations</li><li>Account linked to a phone number and verified</li></ul><p><strong>2. Configure Multiple Accounts</strong></p><p>Add multiple Google accounts and distribute requests through rotation:</p><ul><li>Configure at least 2-3 accounts</li><li>Use <code>account_selection_strategy: &quot;hybrid&quot;</code> strategy (default)</li><li>Automatically switch accounts when encountering rate limits</li></ul><p><strong>3. Control Usage</strong></p><ul><li>Avoid intensive requests in short periods</li><li>Reduce the number of parallel agents</li><li>Set <code>max_rate_limit_wait_seconds: 0</code> in <code>antigravity.json</code> to fail fast instead of retrying</li></ul><p><strong>4. Monitor Account Status</strong></p><p>Regularly check account status:</p><ul><li>View <code>rateLimitResetTimes</code> in <code>~/.config/opencode/antigravity-accounts.json</code></li><li>Enable debug logging: <code>OPENCODE_ANTIGRAVITY_DEBUG=1 opencode</code></li><li>Pause usage for 24-48 hours when encountering 403/429 errors</li></ul><p><strong>5. &quot;Warm Up&quot; in the Official Interface First</strong></p><p>Effective method reported by community users:</p><ol><li>Log in to <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a> in your browser</li><li>Run a few simple prompts (such as &quot;Hello&quot;, &quot;What is 2+2&quot;)</li><li>Use the plugin after 5-10 successful calls</li></ol><p><strong>Principle</strong>: Using the account through the official interface signals to Google that this is normal user behavior, reducing the risk of being flagged.</p><h3 id="❌-practices-to-avoid" tabindex="-1">❌ Practices to Avoid <a class="header-anchor" href="#❌-practices-to-avoid" aria-label="Permalink to &quot;❌ Practices to Avoid&quot;">​</a></h3><ul><li>❌ Create a brand new Google account specifically for this plugin</li><li>❌ Subscribe to Pro/Ultra immediately on newly registered accounts</li><li>❌ Use your only critical service account (such as work email)</li><li>❌ Repeatedly retry after triggering 429 limits</li><li>❌ Launch a large number of parallel agents simultaneously</li><li>❌ Commit <code>antigravity-accounts.json</code> to version control</li></ul><hr><h2 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h2><h3 id="q-my-account-has-been-banned-can-i-appeal" tabindex="-1">Q: My account has been banned. Can I appeal? <a class="header-anchor" href="#q-my-account-has-been-banned-can-i-appeal" aria-label="Permalink to &quot;Q: My account has been banned. Can I appeal?&quot;">​</a></h3><p><strong>A: No.</strong></p><p>If a ban or shadow ban is triggered by Google&#39;s abuse detection through this plugin, it typically cannot be recovered through appeals. Reasons:</p><ul><li>Bans are automatically triggered based on API usage patterns</li><li>Google takes a strict stance on the use of unofficial tools</li><li>Appeals require explaining the tool&#39;s purpose, but this plugin itself may be considered a violation</li></ul><p><strong>Recommendations</strong>:</p><ul><li>Use other unaffected accounts</li><li>If all accounts are banned, use <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a> directly</li><li>Avoid continuing to try on banned accounts</li></ul><h3 id="q-will-using-this-plugin-definitely-result-in-a-ban" tabindex="-1">Q: Will using this plugin definitely result in a ban? <a class="header-anchor" href="#q-will-using-this-plugin-definitely-result-in-a-ban" aria-label="Permalink to &quot;Q: Will using this plugin definitely result in a ban?&quot;">​</a></h3><p><strong>A: Not necessarily.</strong></p><p>Most users use this plugin without issues. Risk depends on:</p><ul><li>Account age and historical behavior</li><li>Usage frequency and request patterns</li><li>Whether best practices are followed</li></ul><p><strong>Risk Assessment</strong>:</p><ul><li>Old account + moderate usage + multi-account rotation → Low risk</li><li>New account + intensive requests + single account → High risk</li></ul><h3 id="q-what-s-the-difference-between-shadow-banning-and-rate-limiting" tabindex="-1">Q: What&#39;s the difference between shadow banning and rate limiting? <a class="header-anchor" href="#q-what-s-the-difference-between-shadow-banning-and-rate-limiting" aria-label="Permalink to &quot;Q: What&#39;s the difference between shadow banning and rate limiting?&quot;">​</a></h3><p><strong>A: Fundamentally different, with different recovery methods.</strong></p><table tabindex="0"><thead><tr><th>Feature</th><th>Shadow Ban</th><th>Rate Limiting (429)</th></tr></thead><tbody><tr><td>Trigger Cause</td><td>Abuse detection, flagged as suspicious</td><td>Request frequency exceeds quota</td></tr><tr><td>Error Code</td><td>403 or silent failure</td><td>429 Too Many Requests</td></tr><tr><td>Duration</td><td>Days to weeks</td><td>Hours to a day</td></tr><tr><td>Recovery Method</td><td>Cannot recover, need to use other accounts</td><td>Wait for reset or switch accounts</td></tr><tr><td>Preventable</td><td>Follow best practices to reduce risk</td><td>Control request frequency</td></tr></tbody></table><h3 id="q-can-i-use-an-enterprise-google-account" tabindex="-1">Q: Can I use an enterprise Google account? <a class="header-anchor" href="#q-can-i-use-an-enterprise-google-account" aria-label="Permalink to &quot;Q: Can I use an enterprise Google account?&quot;">​</a></h3><p><strong>A: Not recommended.</strong></p><p>Enterprise accounts are typically tied to critical services and data, making bans more severe. Additionally:</p><ul><li>Enterprise accounts are scrutinized more strictly</li><li>May violate the organization&#39;s IT policies</li><li>Risk is borne personally but affects the team</li></ul><p><strong>Recommendation</strong>: Use personal accounts.</p><h3 id="q-can-multiple-accounts-completely-avoid-bans" tabindex="-1">Q: Can multiple accounts completely avoid bans? <a class="header-anchor" href="#q-can-multiple-accounts-completely-avoid-bans" aria-label="Permalink to &quot;Q: Can multiple accounts completely avoid bans?&quot;">​</a></h3><p><strong>A: Cannot completely avoid, but can reduce impact.</strong></p><p>The role of multiple accounts:</p><ul><li>Distribute requests, reducing the probability of single accounts triggering limits</li><li>When one account is banned, other accounts remain available</li><li>Automatically switch when encountering limits, improving availability</li></ul><p><strong>But multiple accounts are not a &quot;silver bullet&quot;</strong>:</p><ul><li>If all accounts trigger abuse detection, they may all be banned</li><li>Don&#39;t abuse multiple accounts for intensive requests</li><li>Each account still needs to follow best practices</li></ul><hr><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>After reading this lesson, you should know:</p><ul><li>[ ] Using this plugin may violate Google ToS, use at your own risk</li><li>[ ] New account + Pro/Ultra subscription is a high-risk scenario</li><li>[ ] Using established Google accounts is recommended</li><li>[ ] Configuring multiple accounts can distribute risk</li><li>[ ] Accounts cannot be recovered through appeals after being banned</li><li>[ ] Controlling request frequency and usage is important</li></ul><hr><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>This lesson introduced the potential risks of using the Antigravity Auth plugin:</p><ol><li><strong>Core Risk</strong>: May violate Google ToS, accounts may be banned or shadow banned</li><li><strong>High-Risk Scenarios</strong>: New accounts, new account + subscription, intensive requests, single critical account</li><li><strong>Best Practices</strong>: Use established accounts, configure multiple accounts, control usage, monitor status, &quot;warm up&quot; first</li><li><strong>FAQ</strong>: Cannot appeal, risk varies by individual, multiple accounts can reduce impact</li></ol><p>Before using this plugin, carefully evaluate the risk. If you cannot accept the potential consequences of account bans, we recommend using <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a> directly.</p><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><p>This lesson content is based on the risk warning section of the project README documentation (README.md:23-40), and does not involve specific code implementation.</p><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Lines</th></tr></thead><tbody><tr><td>ToS Warning Statement</td><td><a href="https://github.com/NoeFabris/opencode-antigravity-auth/blob/main/README.md#L23-L40" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>23-40</td></tr></tbody></table></details>',99)])])}const p=t(n,[["render",s]]);export{g as __pageData,p as default};
